    18→const server = http.createServer((req, res) => {
    19→  let urlPath = req.url.split('?')[0];
    20→
    21→  // Serve landing page at root
    22→  if (urlPath === '/' || urlPath === '') {
    23→    const landingPath = path.join(__dirname, 'index.html');
    24→    fs.readFile(landingPath, (err, data) => {
    25→      if (err) {
    26→        res.writeHead(302, { Location: '/html/onboarding-1.html' });
    27→        res.end();
    28→        return;
    29→      }
    30→      res.writeHead(200, { 'Content-Type': 'text/html' });
    31→      res.end(data);
    32→    });
    33→    return;
    34→  }
    35→
    36→  // If someone requests /onboarding-*.html directly, redirect to /html/onboarding-*.html
    37→  if (/^\/onboarding-\d+\.html$/.test(urlPath)) {
    38→    res.writeHead(302, { Location: '/html' + urlPath });
    39→    res.end();
    40→    return;
    41→  }
    42→
    43→  // If someone requests /register.html directly, redirect to /html/register.html
    44→  if (/^\/[a-z-]+\.html$/.test(urlPath)) {
    45→    res.writeHead(302, { Location: '/html' + urlPath });
    46→    res.end();
    47→    return;
    48→  }
    49→
    50→  const filePath = path.join(__dirname, urlPath);
    51→
    52→  fs.readFile(filePath, (err, data) => {
    53→    if (err) {
    54→      res.writeHead(404, { 'Content-Type': 'text/plain' });
    55→      res.end('404 Not Found: ' + urlPath);
    56→      return;
    57→    }
    58→
    59→    const ext = path.extname(filePath).toLowerCase();
    60→    const contentType = mimeTypes[ext] || 'application/octet-stream';
    61→
    62→    res.writeHead(200, { 'Content-Type': contentType });
    63→    res.end(data);
    64→  });
    65→});
