# ── Process files ────────────────────────────────────────────────────────
def add_notif_to_page(content):
    # 1. Add CSS before </style> (first occurrence)
    if '/* ── Notification Dropdown ── */' not in content:
        content = content.replace('</style>', NOTIF_CSS + '\n  </style>', 1)

    # 2. Replace old notif-btn with new wrapped version
    old1 = '<div class="notif-btn">\n          🔔\n          <div class="notif-badge"></div>\n        </div>'
    old2 = '<div class="notif-btn">🔔<div class="notif-badge"></div></div>'
    old3 = '<div class="notif-btn">\n            🔔\n            <div class="notif-badge"></div>\n          </div>'
    # try each pattern
    for old in [old1, old2, old3]:
        if old in content:
            content = content.replace(old, NOTIF_HTML, 1)
            break
    else:
        # fallback: regex
        content = re.sub(r'<div class="notif-btn"[^>]*>\s*🔔\s*<div class="notif-badge[^>]*></div>\s*</div>',
                         NOTIF_HTML, content, count=1)

    # 3. Add JS before closing </script> (last one)
    if 'function toggleNotif' not in content:
        content = re.sub(r'(</script>\s*</body>)', NOTIF_JS + r'\n  \1', content[::-1], count=1)[::-1]
        # try again simpler
        if 'function toggleNotif' not in content:
            content = content.replace('</script>', NOTIF_JS + '\n  </script>', 1)

    return content

# Apply to all admin pages
import glob
pages = glob.glob('webapp/*.html')
pages = [p for p in pages if 'login' not in p and 'forgot' not in p]

for fp in pages:
    with open(fp) as f:
        c = f.read()

    fname = fp.replace('webapp/', '')

    # Pakistani names
    if fname == 'user-management.html':
        for old, new in um_names:
            c = c.replace(old, new)
    elif fname == 'subscription-records.html':
        for old, new in sr_names:
            c = c.replace(old, new)
    elif fname == 'admin-dashboard.html':
        for old, new in dash_names:
            c = c.replace(old, new)
        # Add dashboard search JS
        if 'function dashSearch' not in c:
            c = c.replace('function logout()', 'function dashSearch(q) {\n      q = q.toLowerCase().trim();\n      document.querySelectorAll(\'.user-name-sm\').forEach(el => {\n        const row = el.closest(\'tr\'); if (!row) return;\n        row.style.display = (!q || el.textContent.toLowerCase().includes(q)) ? \'\' : \'none\';\n      });\n    }\n\n    function logout()')
        # Wire up search input
        c = c.replace('placeholder="Search users, transactions, or reports…">',
                      'placeholder="Search users, transactions, or reports…" oninput="dashSearch(this.value)">')

    # Fix payment-management nav-sub CSS conflict
    if fname == 'payment-management.html':
        c = re.sub(
            r'\.nav-sub\s*\{[^}]*display:\s*flex[^}]*\}',
            '/* nav-sub accordion handled below */',
            c
        )
        c = c.replace('.nav-sub:hover { background: #f5f7fd; color: var(--text); }', '')
        c = c.replace('.nav-sub.active { color: var(--active-color); font-weight: 600; }', '')
        c = c.replace('.nav-sub-dot { width: 6px; height: 6px; border-radius: 50%; background: var(--active-color); flex-shrink: 0; }', '')

    # Add notification bell
    c = add_notif_to_page(c)

    with open(fp, 'w') as f:
        f.write(c)
    print(f'Updated: {fp}')

print('All done!')
